function isValidTag(tag) {
    if (tag.length === 0 || tag[0].toUpperCase() !== tag[0]) {
        return false;
    }
    for (let i = 0; i < tag.length - 1; i++) {
        if (tag[i].toUpperCase() === tag[i + 1].toUpperCase()) {
            return false;
        }
    }
    return true;
}

