class Solution:
    def isValidTag(self, tag: str) -> bool:
        if len(tag) == 0 or tag[0].upper() != tag[0]:
            return False
        for i in range(len(tag) - 1):
            if tag[i].upper() == tag[i + 1].upper():
                return False
        return True
